    examTips: [
      "Know the classes of hemorrhagic shock (I-IV) and the corresponding estimated blood loss and clinical signs",
      "Understand why crystalloid-heavy resuscitation is harmful in hemorrhage (dilutional coagulopathy, hypothermia)",
      "TXA must be given within 3 hours of injury — timing is a commonly tested detail",
      "Know the 1:1:1 balanced transfusion ratio and why it is preferred over PRBC-heavy approaches",
      "Understand that normal vital signs do not rule out significant hemorrhage — compensatory mechanisms mask early blood loss",
    ],
    flashcards: [
      { id: "hem-1", question: "What defines massive hemorrhage?", answer: "Loss of ≥1 total blood volume in 24 hours (~5L in 70 kg adult), loss of 50% blood volume in 3 hours, or bleeding rate ≥150 mL/min.", category: "Definition" },
      { id: "hem-2", question: "What is the lethal triad in hemorrhagic shock?", answer: "Hypothermia, acidosis, and coagulopathy. These three conditions form a self-perpetuating cycle that worsens hemorrhage and must be actively broken.", category: "Pathophysiology" },
      { id: "hem-3", question: "What is the recommended blood product ratio in massive transfusion?", answer: "1:1:1 ratio of packed red blood cells (PRBC), fresh frozen plasma (FFP), and platelets. This balanced approach mimics whole blood replacement.", category: "Management" },
      { id: "hem-4", question: "What is permissive hypotension and what is the target?", answer: "Accepting a lower-than-normal BP (target SBP 80-90 mmHg) until surgical hemorrhage control is achieved. Higher pressures can dislodge clots and worsen bleeding.", category: "Management" },
      { id: "hem-5", question: "What is TXA (tranexamic acid) and when must it be given?", answer: "An antifibrinolytic drug (1 g IV over 10 min). Must be given within 3 hours of injury onset for benefit. It prevents clot breakdown and reduces hemorrhage mortality.", category: "Medication" },
      { id: "hem-6", question: "What are the four classes of hemorrhagic shock?", answer: "Class I: <15% loss (compensated). Class II: 15-30% (tachycardia, anxiety). Class III: 30-40% (hypotension, confusion). Class IV: >40% (life-threatening, lethargy/obtundation).", category: "Assessment" },
      { id: "hem-7", question: "Why is hypothermia dangerous in hemorrhage?", answer: "Hypothermia impairs clotting factor enzymatic function, reduces platelet aggregation, and increases fibrinolysis — directly worsening coagulopathy and bleeding.", category: "Pathophysiology" },
      { id: "hem-8", question: "What temperature should be targeted during massive transfusion?", answer: "≥36°C. Use fluid warmers for all blood products and IV fluids. Apply active warming devices (Bair Hugger, warm blankets) to the patient.", category: "Management" },
      { id: "hem-9", question: "What electrolyte abnormality occurs with massive transfusion and why?", answer: "Hypocalcemia, caused by citrate in stored blood products chelating ionized calcium. Monitor ionized calcium and replace with calcium gluconate or calcium chloride.", category: "Lab Values" },
      { id: "hem-10", question: "What fibrinogen level requires replacement during hemorrhage?", answer: "<1.5 g/L (some protocols use <2.0 g/L). Fibrinogen is the first clotting factor to reach critically low levels. Replace with cryoprecipitate or fibrinogen concentrate.", category: "Lab Values" },
      { id: "hem-11", question: "How much does one unit of PRBC raise hemoglobin?", answer: "Approximately 1 g/dL (10 g/L). In active hemorrhage, serial hemoglobin values may not accurately reflect blood loss due to hemodilution.", category: "Lab Values" },
      { id: "hem-12", question: "What is the earliest clinical sign of hemorrhage?", answer: "Tachycardia and anxiety (sympathetic response). Hypotension is a LATE sign — a healthy adult can lose 30% of blood volume before becoming hypotensive.", category: "Assessment" },
      { id: "hem-13", question: "Why is excessive crystalloid harmful in hemorrhagic resuscitation?", answer: "Crystalloid dilutes clotting factors and platelets (dilutional coagulopathy), does not carry oxygen, can worsen hypothermia if not warmed, and causes tissue edema.", category: "Pathophysiology" },
      { id: "hem-14", question: "What is a Shock Index and how is it interpreted?", answer: "Shock Index = Heart Rate / Systolic BP. Normal is 0.5-0.7. Values >0.9-1.0 suggest significant hemorrhage. Values >1.5 indicate severe shock. It is more sensitive than BP alone.", category: "Assessment" },
      { id: "hem-15", question: "What are signs of citrate toxicity during massive transfusion?", answer: "Hypotension, prolonged QT interval, muscle cramping/tetany, tingling/paresthesias, and cardiac arrhythmias. Caused by hypocalcemia from citrate chelating calcium.", category: "Assessment" },
      { id: "hem-16", question: "What nursing actions are critical during MTP activation?", answer: "Establish large-bore IV access (≥18 gauge, ideally 14-16 gauge), draw baseline labs (CBC, coags, type & screen, fibrinogen, ionized calcium), set up fluid warmer, monitor vitals every 5-15 min, document products administered with times.", category: "Nursing" },
      { id: "hem-17", question: "What is the approximate total blood volume of a 70 kg adult?", answer: "Approximately 5 liters (70 mL/kg). This is used to calculate percentage of blood volume lost and classify hemorrhagic shock.", category: "Pathophysiology" },
      { id: "hem-18", question: "What is damage control resuscitation?", answer: "A strategy prioritizing: permissive hypotension, balanced blood product transfusion (1:1:1), limiting crystalloid, early TXA, active rewarming, and early surgical hemorrhage control.", category: "Management" },
      { id: "hem-19", question: "What lab values should be monitored every 30-60 minutes during MTP?", answer: "CBC (hemoglobin, platelets), coagulation studies (PT/INR, PTT), fibrinogen, ionized calcium, blood gas (pH, lactate, base deficit), and potassium.", category: "Nursing" },
      { id: "hem-20", question: "When should O-negative blood be used vs type-specific blood?", answer: "O-negative (universal donor) is used for immediate emergency transfusion when no time for crossmatch. Switch to type-specific blood as soon as type and screen results are available (usually ~15 minutes).", category: "Management" },
      { id: "hem-21", question: "What is the significance of a worsening base deficit during resuscitation?", answer: "A worsening base deficit (becoming more negative) indicates ongoing tissue hypoperfusion and anaerobic metabolism despite resuscitation — suggests continued hemorrhage or inadequate volume replacement.", category: "Lab Values" },
      { id: "hem-22", question: "What role do tourniquets play in hemorrhage control?", answer: "Tourniquets are first-line for life-threatening extremity hemorrhage. Apply proximal to the wound, tighten until bleeding stops, note the time of application, and do not remove in the field — definitive care will address reperfusion.", category: "Management" },
    ],
