    flashcards: [
      { id: "card-1", question: "What ECG criteria define a STEMI?", answer: "≥1 mm ST elevation in ≥2 contiguous leads, ≥2 mm elevation in V1-V3, or new left bundle branch block (LBBB). Indicates complete coronary occlusion requiring emergent reperfusion.", category: "Assessment" },
      { id: "card-2", question: "What is the door-to-balloon target for STEMI?", answer: "≤90 minutes from hospital arrival to PCI balloon inflation. Every 30 minutes of delay increases mortality. Door-to-needle for fibrinolytics: ≤30 minutes.", category: "Management" },
      { id: "card-3", question: "What are the shockable cardiac arrest rhythms?", answer: "Ventricular Fibrillation (VF) and Pulseless Ventricular Tachycardia (pVT). Treatment: immediate defibrillation + CPR + epinephrine + amiodarone.", category: "Assessment" },
      { id: "card-4", question: "What are the non-shockable cardiac arrest rhythms?", answer: "Asystole and Pulseless Electrical Activity (PEA). Treatment: CPR + epinephrine every 3-5 min + identify/treat reversible causes (H's and T's). Do NOT defibrillate.", category: "Assessment" },
      { id: "card-5", question: "What are the H's and T's of cardiac arrest?", answer: "H's: Hypovolemia, Hypoxia, Hydrogen ion (acidosis), Hypo/Hyperkalemia, Hypothermia. T's: Tension pneumothorax, Tamponade, Toxins, Thrombosis (coronary or pulmonary).", category: "Management" },
      { id: "card-6", question: "What is the dose of epinephrine in adult cardiac arrest?", answer: "1 mg IV/IO every 3-5 minutes. This is NOT weight-based in adults. Given as soon as possible in non-shockable rhythms; after 2nd shock in shockable rhythms.", category: "Medication" },
      { id: "card-7", question: "What is the dose of amiodarone in cardiac arrest?", answer: "First dose: 300 mg IV/IO bolus. Second dose: 150 mg IV/IO. Used for refractory VF/pVT that does not respond to defibrillation and epinephrine.", category: "Medication" },
      { id: "card-8", question: "What are the components of high-quality CPR?", answer: "Rate: 100-120/min. Depth: 5-6 cm (2-2.4 in). Full chest recoil between compressions. Minimize interruptions (<10 sec). Switch compressors every 2 minutes. 30:2 ratio without advanced airway.", category: "Management" },
      { id: "card-9", question: "How do you treat symptomatic bradycardia?", answer: "Atropine 0.5 mg IV (repeat every 3-5 min, max 3 mg). If unresponsive to atropine: transcutaneous pacing or dopamine/epinephrine infusion. Third-degree heart block often requires permanent pacing.", category: "Management" },
      { id: "card-10", question: "What is the first-line treatment for stable SVT?", answer: "Vagal maneuvers first (Valsalva, carotid massage, cold water to face). If unsuccessful: adenosine 6 mg rapid IV push with 20 mL NS flush. If still unsuccessful: adenosine 12 mg.", category: "Management" },
      { id: "card-11", question: "What is Torsades de Pointes and how is it treated?", answer: "A polymorphic ventricular tachycardia associated with prolonged QT interval. Treatment: IV magnesium sulfate 2 g over 10 minutes. If pulseless, defibrillate. Correct underlying cause (electrolytes, QT-prolonging drugs).", category: "Management" },
      { id: "card-12", question: "What atypical MI symptoms should new grads be aware of?", answer: "Women, elderly, and diabetics may present with: fatigue, nausea/vomiting, jaw/back/arm pain, dyspnea, or general malaise WITHOUT classic chest pain. Always maintain high clinical suspicion.", category: "Assessment" },
      { id: "card-13", question: "What happens to survival with each minute of delayed defibrillation?", answer: "Survival decreases by 7-10% per minute of VF/pVT without defibrillation. Defibrillation within 3-5 minutes yields 50-70% survival. This is why early defibrillation is critical.", category: "Pathophysiology" },
      { id: "card-14", question: "What is PEA and what are common causes?", answer: "Pulseless Electrical Activity: organized electrical rhythm on the monitor but no palpable pulse/cardiac output. Common causes: severe hypovolemia, massive PE, cardiac tamponade, tension pneumothorax. Treat the cause.", category: "Assessment" },
      { id: "card-15", question: "How does atrial fibrillation appear on ECG?", answer: "Irregularly irregular rhythm with no discernible P waves (fibrillatory baseline). Ventricular rate varies. Management: rate control (beta-blockers or calcium channel blockers) or rhythm control (cardioversion). Assess stroke risk.", category: "Assessment" },
      { id: "card-16", question: "What are the target parameters for post-cardiac arrest care?", answer: "MAP ≥65 mmHg, targeted temperature management 32-36°C for 24 hrs (comatose patients), PaCO2 35-45 mmHg (avoid hyperventilation), blood glucose 140-180 mg/dL, 12-lead ECG for STEMI evaluation.", category: "Management" },
      { id: "card-17", question: "What energy level is used for defibrillation?", answer: "Biphasic: 120-200 J (device-specific, check manufacturer recommendation). Monophasic: 360 J. Escalate energy if initial shock is unsuccessful.", category: "Management" },
      { id: "card-18", question: "What electrolyte imbalance most commonly causes arrhythmias?", answer: "Potassium. Hypokalemia: U waves, ST depression, increased VF risk. Hyperkalemia: peaked T waves, widened QRS, risk of asystole. Always check K+ in new arrhythmias.", category: "Lab Values" },
      { id: "card-19", question: "How is adenosine administered and why must it be given rapidly?", answer: "6 mg rapid IV push followed immediately by 20 mL NS flush via proximal IV site. Adenosine has a half-life <10 seconds — slow administration is ineffective as the drug is metabolized before reaching the heart.", category: "Medication" },
      { id: "card-20", question: "What is the role of the new grad nurse during a code?", answer: "Perform high-quality chest compressions, assist with defibrillation, draw up medications, document events and timing, assist with airway management, and communicate clearly. Excellent CPR is the most valuable contribution.", category: "Nursing" },
      { id: "card-21", question: "What is synchronized cardioversion and when is it used?", answer: "Synchronized cardioversion delivers a shock timed to the R wave to avoid hitting the T wave (which could cause VF). Used for unstable tachyarrhythmias WITH a pulse: unstable SVT, unstable AFib, unstable VT with pulse.", category: "Management" },
      { id: "card-22", question: "What is the significance of troponin in cardiac emergencies?", answer: "Troponin I and T are cardiac-specific biomarkers released when myocardial cells are damaged. Elevated troponin confirms myocardial injury. Serial levels (0, 3, 6 hours) are used for diagnosis. High-sensitivity troponin can detect injury within 1-3 hours.", category: "Lab Values" },
      { id: "card-23", question: "What drugs are given in acute coronary syndrome (MONA)?", answer: "Morphine (if pain unrelieved by nitro), Oxygen (only if SpO2 <94%), Nitroglycerin (SL or IV), Aspirin (162-325 mg chewed). Note: routine O2 is no longer recommended if SpO2 is adequate.", category: "Medication" },
    ],
